const body = $input.first().json.body || {};
const messages = body.messages || [];

if (messages.length === 0) {
  return [{ json: { ignorar: true, motivo: 'sem_messages' } }];
}

const msg = messages[0];
const wa_id = msg.from || '';
const tipo_msg = msg.type || 'text';

let texto_original = '';
let texto = '';
let interactive_id = null;
let interactive_title = null;

if (tipo_msg === 'text') {
  texto_original = msg.text?.body || '';
  texto = texto_original.trim().toLowerCase();
} else if (tipo_msg === 'interactive') {
  const inter = msg.interactive || {};
  if (inter.type === 'list_reply') {
    interactive_id    = inter.list_reply?.id    || null;
    interactive_title = inter.list_reply?.title || null;
  } else if (inter.type === 'button_reply') {
    interactive_id    = inter.button_reply?.id    || null;
    interactive_title = inter.button_reply?.title || null;
  }
  texto_original = interactive_title || '';
  texto = interactive_id || '';
} else {
  return [{ json: { ignorar: true, motivo: 'tipo_nao_suportado', tipo_msg } }];
}

if (!wa_id) {
  return [{ json: { ignorar: true, motivo: 'sem_wa_id' } }];
}

return [{ json: { wa_id, texto, texto_original, tipo_msg, interactive_id, interactive_title, ignorar: false } }];

// Sessão ativa do Supabase
const httpResp = $input.first().json;
const sessions = Array.isArray(httpResp.body) ? httpResp.body : [];
const session = sessions[0] || null;

// Dados extraídos da mensagem
const ext = $('Extrair Dados').item.json;
const wa_id = ext.wa_id;
const texto = ext.texto || '';
const texto_original = ext.texto_original || '';
const interactive_title = ext.interactive_title || null;

// ── INÍCIO: paciente enviou "teleconsultoria" sem sessão ativa ─
if (!session && texto === 'teleconsultoria') {
  return [{ json: {
    wa_id,
    ignorar: false,
    tipo_resposta: 'texto',
    mensagem: 'Olá, tudo bem? Bem vindo ao serviço de Teleconsultoria IMIP. 😊\n\nMe informa seu *primeiro nome*',
    dados_sessao: { wa_id, step: 'aguardando_nome' },
    concluido: false
  }}];
}

// ── SESSÃO ATIVA ───────────────────────────────────────────────
if (session) {
  const step = session.step;
  const dados = {
    wa_id:             session.wa_id,
    step:              session.step,
    nome:              session.nome,
    sobrenome:         session.sobrenome,
    cpf:               session.cpf,
    hospital:          session.hospital,
    forma_atendimento: session.forma_atendimento,
    tipo_atendimento:  session.tipo_atendimento
  };

  // 1. Nome
  if (step === 'aguardando_nome') {
    dados.nome = texto_original || texto;
    dados.step = 'aguardando_sobrenome';
    return [{ json: {
      wa_id, ignorar: false, tipo_resposta: 'texto',
      mensagem: 'Me informa seu *último nome*',
      dados_sessao: dados, concluido: false
    }}];
  }

  // 2. Sobrenome
  if (step === 'aguardando_sobrenome') {
    dados.sobrenome = texto_original || texto;
    dados.step = 'aguardando_cpf';
    return [{ json: {
      wa_id, ignorar: false, tipo_resposta: 'texto',
      mensagem: `*${dados.nome}*, me informa apenas os números do seu CPF`,
      dados_sessao: dados, concluido: false
    }}];
  }

  // 3. CPF
  if (step === 'aguardando_cpf') {
    dados.cpf = texto_original || texto;
    dados.step = 'aguardando_hospital';
    return [{ json: {
      wa_id, ignorar: false, tipo_resposta: 'texto',
      mensagem: `Muito obrigado *${dados.nome}*, me confirma por favor em qual Hospital você trabalha.`,
      dados_sessao: dados, concluido: false
    }}];
  }

  // 4. Hospital
  if (step === 'aguardando_hospital') {
    dados.hospital = texto_original || texto;
    dados.step = 'aguardando_forma';
    return [{ json: {
      wa_id, ignorar: false, tipo_resposta: 'botoes',
      mensagem: 'Qual forma de atendimento você prefere?',
      dados_sessao: dados, concluido: false
    }}];
  }

  // 5. Forma de atendimento (botões)
  if (step === 'aguardando_forma') {
    const forma = interactive_title || texto_original || texto;
    dados.forma_atendimento = forma;
    dados.step = 'aguardando_tipo';
    return [{ json: {
      wa_id, ignorar: false, tipo_resposta: 'lista',
      mensagem: 'Escolha a especialidade',
      dados_sessao: dados, concluido: false
    }}];
  }

  // 6. Tipo / Especialidade (lista)
  if (step === 'aguardando_tipo') {
    const tipo = interactive_title || texto_original || texto;
    dados.tipo_atendimento = tipo;
    dados.step = 'concluido';
    return [{ json: {
      wa_id, ignorar: false, tipo_resposta: 'texto',
      mensagem: 'Mande uma mensagem única com uma descrição do que você quer discutir e aguarde que a(o) especialista irá te responder em até 72h. 🕐',
      dados_sessao: dados,
      concluido: true,
      solicitacao: {
        wa_id,
        nome:              dados.nome,
        sobrenome:         dados.sobrenome,
        cpf:               dados.cpf,
        hospital:          dados.hospital,
        forma_atendimento: dados.forma_atendimento,
        tipo_atendimento:  tipo,
        status: 'pendente'
      },
      msg_equipe: `🔔 *Nova Solicitação de Teleconsultoria*\n\n👤 ${dados.nome} ${dados.sobrenome}\n📱 WhatsApp: ${wa_id}\n🪪 CPF: ${dados.cpf}\n🏥 Hospital: ${dados.hospital}\n📞 Forma: ${dados.forma_atendimento}\n🩺 Especialidade: ${tipo}\n\n📌 Status: Pendente`
    }}];
  }
}

// Nenhuma ação necessária
return [{ json: { ignorar: true, wa_id } }];

const dados = $input.first().json;
const wa_id = dados.wa_id;
const tipo = dados.tipo_resposta;

let payload;

if (tipo === 'botoes') {
  payload = {
    recipient_type: 'individual',
    to: wa_id,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: dados.mensagem },
      action: {
        buttons: [
          { type: 'reply', reply: { id: 'videochamada',    title: 'Agendar videochamada' } },
          { type: 'reply', reply: { id: 'mensagens_texto', title: 'Mensagens de texto'   } }
        ]
      }
    }
  };
} else if (tipo === 'lista') {
  payload = {
    recipient_type: 'individual',
    to: wa_id,
    type: 'interactive',
    interactive: {
      type: 'list',
      body: { text: dados.mensagem },
      action: {
        button: 'Ver especialidades',
        sections: [{
          title: 'Especialidades',
          rows: [
            { id: 'medico',            title: 'Médica(o)'         },
            { id: 'psicologo',         title: 'Psicologa(o)'      },
            { id: 'nutricionista',     title: 'Nutricionista'     },
            { id: 'assistente_social', title: 'Assistente Social' }
          ]
        }]
      }
    }
  };
} else {
  payload = {
    recipient_type: 'individual',
    to: wa_id,
    type: 'text',
    text: { body: dados.mensagem }
  };
}

return [{ json: { ...dados, payload } }];
